eval("__webpack_require__.r(__webpack_exports__);\n/* harmony export */ __webpack_require__.d(__webpack_exports__, {\n/* harmony export */   latestVersion: () => (/* binding */ latestVersion),\n/* harmony export */   releaseNotes: () => (/* binding */ releaseNotes)\n/* harmony export */ });\nconst releaseNotes = [\n    {\n        version: \"2.0\",\n        date: \"2026-03-18\",\n        title: \"评测升级与超级地图上线\",\n        description: \"2.0 版本聚焦于“认知自己 + 看清外部世界”两条主线。本次更新新增了 PDP 性格评估，补齐了性格评测中心的核心模型矩阵；同时正式上线超级地图模块，让管理者可以把宏观数据与决策语境放在同一画面中理解与表达。我们希望这一版不仅提供结论，更提供可视化的思考入口，让洞察更快落地为行动。\",\n        highlights: [\n            {\n                title: \"PDP 评估正式加入性格评测中心\",\n                content: \"在 MBTI 与 4D 之外，我们新增了 PDP（行为特质动态）评估能力。PDP 更强调“行为风格在真实场景中的表现”，可帮助您识别自己在推动目标、协同团队、处理压力与冲突时的典型倾向。系统会将评测结果转换为可直接执行的管理建议，帮助您把“自我认知”真正连接到“管理动作”。\"\n            },\n            {\n                title: \"超级地图上线：一张图看世界与区域差异\",\n                content: \"超级地图模块现已可在工作流中独立使用。您可以在中国地图与世界地图之间快速切换，结合国家/省份级信息进行对比观察；支持缩放、拖动、点击高亮、样式调节与图片导出，方便将分析结果直接用于会议讨论与汇报材料。地图不仅是展示工具，更是帮助您组织观点、对齐认知的决策画布。\"\n            },\n            {\n                title: \"地图玩法简化：从“看”到“讲”再到“用”\",\n                content: \"为了降低上手门槛，我们将超级地图的推荐使用路径沉淀为三步：先用缩放与筛选快速定位关键区域，再通过高亮与标签聚焦重点对象，最后导出图片用于复盘、讨论与决策沟通。无论是战略扫描、区域比较还是管理汇报，您都可以在同一界面完成“发现问题—表达结论—推动行动”的闭环。\"\n            }\n        ]\n    },\n    {\n        version: \"1.7\",\n        date: \"2026-02-16\",\n        title: \"新增性格评测中心与体验全面优化\",\n        description: \"1.7 版本进行了功能板块的扩展。本次更新最核心的变化是重磅加入了“性格评测”模块——这不仅仅是一个新入口，而是新增了一整套独立使用的评测系统与结果展示体系。我们希望通过引入成熟的心理学模型，帮助您在管理决策之外，也能从“人”的角度看清自己的底层驱动力与团队位置。同时，本次更新也涵盖了安全策略的加固与界面交互的细节打磨。\",\n        highlights: [\n            {\n                title: \"两大核心评测模型上线\",\n                content: \"我们在独立的评测页面中首批上线了两套高频模型：MBTI 与 4D 高管坐标。MBTI 侧重于挖掘您在高压场景下的潜意识反应，帮助您看清自己的习惯性决策模式与沟通风格；4D 模型则采用更客观的“坐标系”视角，从“关注人vs关注事”和“偏向直觉vs偏向感觉”两个维度，帮您快速定位自己在团队中的管理象限。后续我们还将持续引入更多类型的评测工具，覆盖不同阶段的管理场景。\"\n            },\n            {\n                title: \"评测结果结构化呈现\",\n                content: \"为了降低使用门槛，我们对评测结果的展示进行了深度优化。系统会自动将复杂的心理学概念转化为结构化的管理语言，您不需要学习晦涩的理论，就能直接读懂结论。无论是对自己性格优劣势的判断，还是对沟通风格的建议，都做到了一目了然，让评测结果真正成为可参考的自我认知说明书。\"\n            },\n            {\n                title: \"安全加固与交互体验升级\",\n                content: \"在功能扩展的同时，我们也夯实了地基。本次版本新增并提升了多项安全保护措施，确保数据流转的稳妥可靠。在界面体验上，我们对页面布局、文字可读性以及操作的顺滑度进行了全方位的细节优化。现在的系统不仅看起来更清晰，用起来也更自然顺手，即使是初次使用的用户也能零成本快速上手。\"\n            }\n        ]\n    },\n    {\n        version: \"1.5\",\n        date: \"2026-02-10\",\n        title: \"核心体验升级：组织合伙人与思维可视化\",\n        description: \"本次更新是一次核心能力的跨越，我们将 AI 的角色定位从单纯的高管教练延伸到了组织战略合伙人。我们深刻理解，在复杂的组织管理中，单纯的理论模型往往难以解决充满灰度的实际问题，因此我们重构了工具的内核与交互体验。\",\n        highlights: [\n            {\n                title: \"新增组织合伙人实战模块\",\n                content: \"针对人力资源合作伙伴及业务管理者，我们新增了四个高频场景的实战工具。这套工具箱摒弃了传统的表格思维，转而采用更敏锐的业务协同与战时视角。无论是利用业务需求解码器听懂负责人的话外音，还是通过关键人才盘点识别团队中的破局者与负资产，亦或是利用团队协同参谋来平衡组织的能量短板，系统都能提供具备深度的决策支持。此外，新增的谈心锦囊能针对不同类型的员工生成有策略的沟通剧本，帮助管理者在每一次对话中建立信任。\"\n            },\n            {\n                title: \"全系工具配备深度使用说明书\",\n                content: \"为了让每一项工具都能精准匹配您的管理痛点，我们为平台上的所有工具增设了详尽的使用说明书。现在，在启用任何一个模型前，您都可以清晰地了解到它的核心设计理念、最佳适用场景以及预期的交付结果。这不仅是一份操作指南，更是一张索引不同管理难题的作战地图，帮助您在面对复杂局势时快速找到最顺手的武器。\"\n            },\n            {\n                title: \"交互重构与思维可视化\",\n                content: \"我们深知深刻的洞察需要运算时间，但不代表用户需要枯燥等待。本次更新引入了全新的思维可视化引擎，实现了点击即响应的极速体验。在系统进行深度推演的过程中，界面将实时展示思维的流转路径——从扫描管理风格、推演风险边界到构建破局话术。这种透明化的思考过程，让您不仅获得一个结果，更能见证一个专业决策诞生的全逻辑。\"\n            }\n        ]\n    },\n    {\n        version: \"1.3\",\n        date: \"2026-02-08\",\n        title: \"架构重塑：系统化管理视界\",\n        description: \"为了帮助您更直观地调用思维工具，我们对产品架构进行了系统级重塑。我们尝试用更科学的视角，帮您建立全局的管理坐标系。\",\n        highlights: [\n            {\n                title: \"三大维度的全景分类\",\n                content: \"我们将所有思维工具重新划分为“看自己”、“看团队”、“看系统”三大核心领域。这种分类方式不仅是功能的索引，更是管理视角的引导——帮助您从内向外、由点及面地审视局势。同时，我们为每个工具补充了深度的背景描述与适用边界，帮助您在面对复杂局势时，能迅速定位到最顺手的破局武器。\"\n            },\n            {\n                title: \"基础内参质量跃升\",\n                content: \"在底层模型层面，我们也对常规对话模式进行了深度调优。通过优化上下文理解能力与逻辑推理链条，即使在不使用特定工具的“通用模式”下，AI 的回复也将更加犀利、切中要害，确保您的每一次提问都能获得高水准的回响。\"\n            }\n        ]\n    },\n    {\n        version: \"1.2\",\n        date: \"2026-02-07\",\n        title: \"核心模块：高管思维工具箱\",\n        description: \"在通用对话之外，高管面临的往往是结构化的难题。本次更新，我们首次引入了“思维工具箱”概念，将顶级的管理学模型封装为可直接调用的 AI 技能。\",\n        highlights: [\n            {\n                title: \"11 款实战决策模型\",\n                content: \"我们精选了 11 个高频管理场景（如决策沙盘、冲突谈判、危机公关等），将其转化为标准化的思维工具。现在，您不再需要费力地去引导 AI，只需点击对应的工具，AI 参谋即刻切换至专家视角，为您提供具备框架感与落地性的解决方案。这是从“自由问答”向“专业咨询”的一次关键跨越。\"\n            }\n        ]\n    },\n    {\n        version: \"1.1\",\n        date: \"2026-02-06\",\n        title: \"体验升级：构建私人决策档案\",\n        description: \"随着交互的深入，您的每一次推演都将成为宝贵的思维资产。本次更新重点完善了账户体系与个性化配置，旨在为您打造一个连续、私密的战略档案库。\",\n        highlights: [\n            {\n                title: \"思维资产的云端同步\",\n                content: \"新增用户注册与登录功能。现在，您的每一次战略沙盘推演、每一场模拟复盘都将被安全加密并云端同步。无论设备如何切换，您的决策脉络都将完好保存，确保思维的连续性与安全性。\"\n            },\n            {\n                title: \"多维度的参谋风格定制\",\n                content: \"我们引入了更细致的设置选项。您可以根据当下的思考偏好，调整 AI 参谋的交互风格——是作为严谨犀利的数据分析师，还是作为温和睿智的幕后军师。同时，新增的中英文双语切换与深色模式支持，确保您在深夜复盘或跨国语境下，都能获得最舒适的阅读体验。\"\n            }\n        ]\n    },\n    {\n        version: \"1.0\",\n        date: \"2026-02-05\",\n        title: \"全新上线：高管 AI 内参 (Executive AI Insider)\",\n        description: \"这是我们为您构建的专属决策思考空间。在充满噪音的商业环境中，“高管 AI 内参”致力于利用最前沿的通用人工智能技术，为您提供冷静、客观且具备深度的战略推演服务。这不仅仅是一个对话框，而是您随身携带的数字智囊团。\",\n        highlights: [\n            {\n                title: \"双引擎驱动的决策支持\",\n                content: \"系统集成了 DeepSeek 与豆包两大顶尖模型，以适应您不同的决策节奏。启用“Pro 深度模式”，AI 将进行数十秒的高强度思维链（CoT）推演，为您拆解复杂的战略难题；若需快速梳理思路，“Fast 极速模式”则能在毫秒级响应中，依然保持敏锐的洞察力与高质量的交付。\"\n            },\n            {\n                title: \"沉浸式思考环境\",\n                content: \"我们摒弃了一切干扰元素，构建了一个纯净的交互界面。在这里，没有冗余的信息流，只有您和您的 AI 参谋，共同面对那些棘手的商业挑战。\"\n            }\n        ]\n    }\n];\nconst latestVersion = \"2.0\";\n//# sourceURL=[module]\n//# sourceMappingURL=data:application/json;charset=utf-8;base64,\n//# sourceURL=webpack-internal:///(ssr)/./lib/release_notes.ts\n");

